```typescript
import { setup, assign } from 'xstate';

type Events =
  | { type: 'LOAD'; src: string }
  | { type: 'BUFFERED' }
  | { type: 'PLAY' }
  | { type: 'PAUSE' }
  | { type: 'SEEK'; time: number }
  | { type: 'END' }
  | { type: 'ERROR'; message: string }
  | { type: 'RESET' };

export const mediaPlayerMachine = setup({
  types: {
    context: {} as { src: string; position: number; error: string | null },
    events: {} as Events
  },
  actions: {
    setSrc: assign({
      src: ({ event }) => (event.type === 'LOAD' ? event.src : ''),
      position: 0,
      error: null
    }),
    seekTo: assign({
      position: ({ event }) => (event.type === 'SEEK' ? event.time : 0)
    }),
    setError: assign({
      error: ({ event }) => (event.type === 'ERROR' ? event.message : null)
    })
  }
}).createMachine({
  id: 'mediaPlayer',
  initial: 'idle',
  context: { src: '', position: 0, error: null },
  on: {
    ERROR: { target: '.error', actions: 'setError' },
    SEEK: { actions: 'seekTo' }
  },
  states: {
    idle: { on: { LOAD: { target: 'buffering', actions: 'setSrc' } } },
    buffering: { on: { BUFFERED: 'playing' } },
    playing: { on: { PAUSE: 'paused', END: 'ended' } },
    paused: { on: { PLAY: 'playing' } },
    ended: { on: { LOAD: { target: 'buffering', actions: 'setSrc' } } },
    error: { on: { RESET: 'idle' } }
  }
});
```

Use `after` for the stall timeout and a `BUFFERED` event for the happy path. Both target `playing`, so recovery and the fast path share one destination.

```typescript
import { setup, assign } from 'xstate';

export const stallMachine = setup({
  types: {
    context: {} as { stalls: number },
    events: {} as { type: 'BUFFERED' } | { type: 'STALL' }
  },
  actions: {
    bumpStall: assign({ stalls: ({ context }) => context.stalls + 1 })
  }
}).createMachine({
  id: 'stall',
  initial: 'playing',
  context: { stalls: 0 },
  states: {
    playing: { on: { STALL: { target: 'buffering', actions: 'bumpStall' } } },
    buffering: {
      on: { BUFFERED: 'playing' },
      after: { 3000: 'playing' }
    }
  }
});
```

Seeking is an internal transition on the `playing` state: it updates `context.position` via `assign` but does not change the state node, so playback continues uninterrupted. Declaring the action in `setup.actions` keeps the state body string-referenced.

```typescript
import { setup, assign } from 'xstate';

type Ev =
  | { type: 'PLAY' }
  | { type: 'PAUSE' }
  | { type: 'SEEK'; to: number };

export const seekMachine = setup({
  types: {
    context: {} as { position: number },
    events: {} as Ev
  },
  actions: {
    seekTo: assign({
      position: ({ event }) => (event.type === 'SEEK' ? event.to : 0)
    })
  }
}).createMachine({
  id: 'seek',
  initial: 'paused',
  context: { position: 0 },
  states: {
    paused: { on: { PLAY: 'playing' } },
    playing: {
      on: {
        PAUSE: 'paused',
        SEEK: { actions: 'seekTo' }
      }
    }
  }
});
```

