Invoke a `fromCallback` actor scoped to the `playing` state. Entering starts the interval, exiting tears it down automatically.

```typescript
import { setup, fromCallback, assign } from 'xstate';

type Ev = { type: 'PLAY' } | { type: 'PAUSE' } | { type: 'TICK' };

export const heartbeatMachine = setup({
  types: {
    context: {} as { seconds: number },
    events: {} as Ev
  },
  actors: {
    ticker: fromCallback<{ type: 'TICK' }>(({ sendBack }) => {
      const id = setInterval(() => sendBack({ type: 'TICK' }), 1000);
      return () => clearInterval(id);
    })
  },
  actions: {
    bump: assign({ seconds: ({ context }) => context.seconds + 1 })
  }
}).createMachine({
  id: 'heartbeat',
  initial: 'paused',
  context: { seconds: 0 },
  states: {
    paused: { on: { PLAY: 'playing' } },
    playing: {
      invoke: { src: 'ticker' },
      on: { PAUSE: 'paused', TICK: { actions: 'bump' } }
    }
  }
});
```

