import { setup, assign } from 'xstate';

type Ev =
  | { type: 'START' }
  | { type: 'SCORE'; points: number }
  | { type: 'DIE' }
  | { type: 'RESTART' };

export const gameMachine = setup({
  types: {
    context: {} as { score: number; best: number },
    events: {} as Ev
  },
  actions: {
    addScore: assign({
      score: ({ context, event }) =>
        event.type === 'SCORE' ? context.score + event.points : context.score
    }),
    finalize: assign({
      best: ({ context }) => Math.max(context.best, context.score)
    }),
    reset: assign({ score: 0 })
  }
}).createMachine({
  id: 'game',
  initial: 'title',
  context: { score: 0, best: 0 },
  states: {
    title: { on: { START: { target: 'playing', actions: 'reset' } } },
    playing: {
      on: {
        SCORE: { actions: 'addScore' },
        DIE: { target: 'gameover', actions: 'finalize' }
      }
    },
    gameover: { on: { RESTART: 'title' } }
  }
});
