A parallel root has independent regions that are always active together. Putting a `paused/running` region next to a `score` region lets you pause game flow without tearing down score tracking — both live side by side, and events only affect the region whose state handles them.

```typescript
import { setup, assign } from 'xstate';

type Ev = { type: 'PAUSE' } | { type: 'RESUME' } | { type: 'SCORE'; pts: number };

export const loopMachine = setup({
  types: {
    context: {} as { score: number },
    events: {} as Ev
  },
  actions: {
    addPts: assign({
      score: ({ context, event }) =>
        event.type === 'SCORE' ? context.score + event.pts : context.score
    })
  }
}).createMachine({
  id: 'loop',
  type: 'parallel',
  context: { score: 0 },
  states: {
    flow: {
      initial: 'running',
      states: {
        running: { on: { PAUSE: 'paused' } },
        paused: { on: { RESUME: 'running' } }
      }
    },
    scoring: {
      on: { SCORE: { actions: 'addPts' } }
    }
  }
});
```

