import { setup, fromCallback, assign } from 'xstate';

type Ev =
  | { type: 'KEY'; combo: string }
  | { type: 'START' }
  | { type: 'STOP' };

export const shortcutMachine = setup({
  types: {
    context: {} as { last: string | null },
    events: {} as Ev
  },
  actors: {
    keyListener: fromCallback<{ type: 'KEY'; combo: string }>(({ sendBack }) => {
      const handler = (e: KeyboardEvent): void => {
        sendBack({ type: 'KEY', combo: `${e.ctrlKey ? 'C-' : ''}${e.key}` });
      };
      globalThis.addEventListener('keydown', handler);
      return () => globalThis.removeEventListener('keydown', handler);
    })
  },
  actions: {
    remember: assign({
      last: ({ event }) => (event.type === 'KEY' ? event.combo : null)
    })
  }
}).createMachine({
  id: 'shortcut',
  initial: 'idle',
  context: { last: null },
  states: {
    idle: { on: { START: 'listening' } },
    listening: {
      invoke: { src: 'keyListener' },
      on: {
        KEY: { actions: 'remember' },
        STOP: 'idle'
      }
    }
  }
});
```

Return the cleanup function from inside `fromCallback`; XState calls it when the state invoking the actor exits, so unsubscribing is automatic.

```typescript
import { setup, fromCallback } from 'xstate';

type Ev = { type: 'KEY'; key: string };

export const keyMachine = setup({
  types: {
    context: {} as Record<string, never>,
    events: {} as Ev
  },
  actors: {
    keys: fromCallback<{ type: 'KEY'; key: string }>(({ sendBack }) => {
      const h = (e: KeyboardEvent): void => sendBack({ type: 'KEY', key: e.key });
      globalThis.addEventListener('keydown', h);
