Use a guarded transition array on the KEY event: each entry matches one combo and fires a named action from `setup.actions`. A final unguarded entry acts as a fallback no-op so unknown combos don't crash.

```typescript
import { setup } from 'xstate';

type Ev = { type: 'KEY'; combo: string };

export const dispatcher = setup({
  types: {
    context: {} as Record<string, never>,
    events: {} as Ev
  },
  actions: {
    save: () => {},
    quit: () => {},
    noop: () => {}
  },
  guards: {
    isSave: ({ event }) => event.combo === 'C-s',
    isQuit: ({ event }) => event.combo === 'C-q'
  }
}).createMachine({
  id: 'dispatcher',
  initial: 'listening',
  context: {},
  states: {
    listening: {
      on: {
        KEY: [
          { guard: 'isSave', actions: 'save' },
          { guard: 'isQuit', actions: 'quit' },
          { actions: 'noop' }
        ]
      }
    }
  }
});
```

