import { setup, fromCallback, raise } from 'xstate';

type Ev =
  | { type: 'KEY'; combo: string }
  | { type: 'UNDO' }
  | { type: 'REDO' };

export const undoMachine = setup({
  types: {
    context: {} as { undos: number; redos: number },
    events: {} as Ev
  },
  actors: {
    keys: fromCallback<{ type: 'KEY'; combo: string }>(({ sendBack }) => {
      const h = (e: KeyboardEvent): void => {
        if (!e.ctrlKey) return;
        sendBack({ type: 'KEY', combo: e.key });
      };
      globalThis.addEventListener('keydown', h);
      return () => globalThis.removeEventListener('keydown', h);
    })
  },
  guards: {
    isUndo: ({ event }) => event.type === 'KEY' && event.combo === 'z',
    isRedo: ({ event }) => event.type === 'KEY' && event.combo === 'y'
  }
}).createMachine({
  id: 'undo',
  initial: 'on',
  context: { undos: 0, redos: 0 },
  states: {
    on: {
      invoke: { src: 'keys' },
      on: {
        KEY: [
          { guard: 'isUndo', actions: raise({ type: 'UNDO' }) },
          { guard: 'isRedo', actions: raise({ type: 'REDO' }) }
        ],
        UNDO: {},
        REDO: {}
      }
    }
  }
});
```

