  },
  guards: {
    underMax: ({ context }) => context.attempts < context.max
  },
  delays: {
    NEXT: ({ context }) => context.delay
  }
}).createMachine({
  id: 'polling',
  initial: 'idle',
  context: { attempts: 0, delay: 500, max: 5 },
  states: {
    idle: { on: { START: { target: 'polling', actions: 'reset' } } },
    polling: {
      after: {
        NEXT: [
          { guard: 'underMax', target: 'polling', reenter: true, actions: 'bump' },
          { target: 'idle' }
        ]
      },
      on: { CANCEL: 'idle' }
    }
  }
});
```

Store the current delay in context and reference it from a named delay. Each re-entry of the polling state bumps it with `assign`, doubling up to a ceiling.

```typescript
