      delay: ({ context }) => Math.min(context.delay * 2, 8000)
    })
  },
  delays: {
    NEXT: ({ context }) => context.delay
  }
}).createMachine({
  id: 'backoff',
  initial: 'polling',
  context: { delay: 500 },
  states: {
    polling: {
      after: { NEXT: { target: 'polling', reenter: true, actions: 'grow' } },
      on: { STOP: 'idle' }
