`enqueueActions` lets you check guards and enqueue typed actions in one place, keeping transition bodies tidy.

```typescript
import { setup, assign, enqueueActions } from 'xstate';

type Ev = { type: 'SELECT'; tab: 'A' | 'B' };

export const dashMachine = setup({
  types: {
    context: {} as { active: 'A' | 'B'; visits: number },
    events: {} as Ev
  },
  actions: {
    setTab: assign({
      active: ({ event }) => (event.type === 'SELECT' ? event.tab : 'A')
    }),
    bumpVisits: assign({ visits: ({ context }) => context.visits + 1 })
  },
  guards: {
    isDifferent: ({ context, event }) =>
      event.type === 'SELECT' && event.tab !== context.active
  }
}).createMachine({
  id: 'dash',
  context: { active: 'A', visits: 0 },
  on: {
    SELECT: {
      actions: enqueueActions(({ enqueue, check }) => {
        if (check('isDifferent')) {
          enqueue('setTab');
          enqueue('bumpVisits');
        }
      })
    }
  }
});
```
